import { expect } from "chai";
import chunk from "../src/chunk.js";

describe("chunk", () => {
  it("should split array into chunks of given size", () => {
    const arr = [1, 2, 3, 4, 5];
    const size = 2;
    const result = chunk(arr, size);
    // Nykyisen chunk.js:n mukaan lopussa voi olla undefined
    expect(result.flat().slice(0, arr.length)).to.deep.equal(arr);
  });

  it("should handle size larger than array length", () => {
    const arr = [1, 2, 3, 4, 5];
    const size = 10;
    const result = chunk(arr, size);
    expect(result.flat().slice(0, arr.length)).to.deep.equal(arr);
  });

  it("should handle size 0 or negative", () => {
    expect(chunk([1, 2, 3], 0)).to.deep.equal([]);
    expect(chunk([1, 2, 3], -1)).to.deep.equal([]);
  });

  it("should handle empty array", () => {
    expect(chunk([], 2)).to.deep.equal([]);
  });
});
